CREATE OR REPLACE TRIGGER CMDKLTDA_TRIGGERTEST_0012
BEFORE INSERT ON CMDKLTD_ACAO_CE
FOR EACH ROW
BEGIN
    IF :NEW.DS_VALOR_CUSTOM = 1 THEN
        :NEW.NRTEST := 11;

    ELSIF :NEW.DS_VALOR_CUSTOM = 2 THEN
        :NEW.DS_VALOR_CUSTOM := 22; 

