CREATE OR REPLACE PACKAGE CMDKLTDA_P_MAT AS

    FUNCTION soma(
        p_num1 NUMBER,
        p_num2 NUMBER
    ) RETURN NUMBER;

    FUNCTION multiplicar(
        p_num1 NUMBER,
        p_num2 NUMBER
    ) RETURN NUMBER;

END CMDKLTDA_P_MAT;
/
CREATE OR REPLACE PACKAGE BODY CMDKLTDA_P_MAT AS

    FUNCTION soma(
        p_num1 NUMBER,
        p_num2 NUMBER
    ) RETURN NUMBER IS
    BEGIN
        RETURN p_num1 + p_num2;
    END;

    FUNCTION multiplicar(
        p_num1 NUMBER,
        p_num2 NUMBER
    ) RETURN NUMBER IS
    BEGIN
        RETURN p_num1 * p_num2;
    END;

END CMDKLTDA_P_MAT;
/

